function shortlisted_startups_for_fund_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('shortlisted_startups_for_fund_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'startup' => Request::lookup('startup', ''),
		'scheme' => Request::val('scheme', ''),
		'recommended_fund' => Request::val('recommended_fund', ''),
		'name_of_founder' => Request::val('name_of_founder', ''),
		'email_of_founder' => Request::val('email_of_founder', ''),
		'phone_number_of_founder' => Request::val('phone_number_of_founder', ''),
		'due_diligence_start' => Request::val('due_diligence_start', ''),
		'terms_agreed' => Request::val('terms_agreed', ''),
		'grant_amount' => Request::val('grant_amount', ''),
		'debt_amount' => Request::val('debt_amount', ''),
		'ocd_or_ccd_amount' => Request::val('ocd_or_ccd_amount', ''),
		'equity_amount' => Request::val('equity_amount', ''),
		'interest_rate' => Request::val('interest_rate', ''),
		'period' => Request::val('period', ''),
		'conversion_formula' => Request::val('conversion_formula', ''),
		'equity_diluted' => Request::val('equity_diluted', ''),
		'comments' => br2nl(Request::val('comments', '')),
		'remarks_1' => br2nl(Request::val('remarks_1', '')),
		'remarks_2' => br2nl(Request::val('remarks_2', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('shortlisted_startups_for_fund_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		shortlisted_startups_for_fund_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

